import{_ as a,o,c as t,an as s}from"./chunks/framework.CZWTm_-p.js";const u=JSON.parse('{"title":"Bundled data: 1861 Hagelloch measles outbreak","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/tutorials/hagelloch-data/README.md","filePath":"getting-started/tutorials/hagelloch-data/README.md","lastUpdated":null}'),l={name:"getting-started/tutorials/hagelloch-data/README.md"};function i(c,e,r,d,n,h){return o(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="Bundled-data:-1861-Hagelloch-measles-outbreak" tabindex="-1">Bundled data: 1861 Hagelloch measles outbreak <a class="header-anchor" href="#Bundled-data:-1861-Hagelloch-measles-outbreak" aria-label="Permalink to &quot;Bundled data: 1861 Hagelloch measles outbreak {#Bundled-data:-1861-Hagelloch-measles-outbreak}&quot;">​</a></h1><p><code>linelist.csv</code> is the 1861 Hagelloch (Germany) measles line list (n = 188 children), the canonical dataset for pairwise survival analysis of transmission. The data were originally collected by Pfeilsticker (1863) and re-analysed by Oesterle (1992), and have been used repeatedly to test transmission models because every case carries a putative infector and a household.</p><p>The copy here is taken verbatim from the <a href="https://github.com/reconhub/outbreaks" target="_blank" rel="noreferrer">outbreaks</a> R package (<code>measles_hagelloch_1861</code>), released under the MIT licence (see <code>LICENSE</code>), which in turn formatted it from <code>hagelloch.df</code> in the <a href="https://CRAN.R-project.org/package=surveillance" target="_blank" rel="noreferrer">surveillance</a> R package. No values have been modified in this copy.</p><p>Columns:</p><ul><li><p><code>case_ID</code>: case id number.</p></li><li><p><code>infector</code>: case id of the putative source of infection (the who-infected-whom ground truth used here only as a comparison target).</p></li><li><p><code>date_of_prodrome</code>: date of onset of prodromal symptoms (taken here as the onset of infectiousness that starts the contact-interval clock).</p></li><li><p><code>date_of_rash</code>: date of onset of rash.</p></li><li><p><code>date_of_death</code>: date of death (<code>NA</code> means recovered).</p></li><li><p><code>age</code>: age in years.</p></li><li><p><code>gender</code>: <code>f</code> / <code>m</code>.</p></li><li><p><code>family_ID</code>: household (family) id, the close-contact group structure.</p></li><li><p><code>class</code>: school class (<code>0</code> preschool, <code>1</code> first class, <code>2</code> second class).</p></li><li><p><code>complications</code>, <code>x_loc</code>, <code>y_loc</code>: complications flag and house coordinates (unused here).</p></li></ul><p>If you use this data in your own work, please cite:</p><blockquote><p>Pfeilsticker, A. (1863). Beiträge zur Pathologie der Masern. M.D. Thesis, Eberhard-Karls-Universität Tübingen.</p><p>Oesterle, H. (1992). Statistische Reanalyse einer Masernepidemie 1861 in Hagelloch. M.D. Thesis, Eberhard-Karls-Universität Tübingen.</p><p>Neal, P. J. and Roberts, G. O. (2004). Statistical inference and model selection for the 1861 Hagelloch measles epidemic. Biostatistics 5(2):249-261.</p></blockquote><p>The pairwise survival method analysed on this page is from:</p><blockquote><p>Kenah, E. (2011). Contact intervals, survival analysis of epidemic data, and estimation of R0. Biostatistics 12(3):548-566. <a href="https://doi.org/10.1093/biostatistics/kxq068" target="_blank" rel="noreferrer">doi:10.1093/biostatistics/kxq068</a></p></blockquote>',9)])])}const f=a(l,[["render",i]]);export{u as __pageData,f as default};
